#include <bits/stdc++.h>
using namespace std;
const int mod=19650827;
int n,h[1003];
long long dp[1003][1003][2];
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&h[i]);
	for(int i=1;i<=n;i++)
		dp[i][i][0]=dp[i][i][1]=1;
	for(int len=2;len<=n;len++)
		for(int l=1;l+len-1<=n;l++){
			int r=l+len-1;
			if(h[l]<h[l+1])
				dp[l][r][0]+=dp[l+1][r][0],dp[l][r][0]%=mod;
			if(h[l]<h[r] && l+1<r)
				dp[l][r][0]+=dp[l+1][r][1],dp[l][r][0]%=mod;
			if(h[l]<h[r])
				dp[l][r][1]+=dp[l][r-1][0],dp[l][r][1]%=mod;
			if(h[r-1]<h[r] && l<r-1)
				dp[l][r][1]+=dp[l][r-1][1],dp[l][r][1]%=mod;
		}
	if(n>1)
		printf("%lld",(dp[1][n][0]+dp[1][n][1])%mod);
	else
		printf("%lld",dp[1][n][0]);
	return 0;
}
